const raw = $input.first().json;
// toolWorkflow (AI Agent) передаёт параметры в $json.query
// executeWorkflow передаёт напрямую в $json
let data = raw;
if (raw.query && typeof raw.query === 'object' && !Array.isArray(raw.query)) {
  data = raw.query;
} else if (typeof raw.input === 'string') {
  try { data = JSON.parse(raw.input); } catch(e) {}
} else if (typeof raw.query === 'string') {
  try { data = JSON.parse(raw.query); } catch(e) {}
}
const violationDate = data.violationDate || data.violation_date || null;
const discoveryDate = data.discoveryDate || data.discovery_date || null;
if (!violationDate || !discoveryDate) {
  throw new Error('check_dates: не переданы обязательные параметры violationDate и discoveryDate. Получено: ' + JSON.stringify(raw));
}
return [{ json: { violationDate, discoveryDate } }];

const r = $input.first().json;
return [{ json: {
  isExpired: r.is_expired === true || r.is_expired === 'true',
  expiredReason: r.expired_reason || null,
  violationDeadline: r.violation_deadline,
  discoveryDeadline: r.discovery_deadline
} }];
